// Extrai o remetente (número) e o texto da mensagem de forma genérica para APIs de WhatsApp
const body = $json.body;
const messageText = (body.text || body.message || body.body || '').trim();
const fromNumber = (body.from || body.phone || body.sender || '').replace(/\D/g, '');

return {
  message: messageText,
  from: fromNumber
};

const results = $input.all();
const msgData = $node["Normalizar Mensagem Entrada"].json;

if (results.length === 0 || !results[0].json.id) {
  return { json: { step: 'DESCONHECIDO', text: msgData.message, from: msgData.from } };
}

const user = results[0].json;
const message = msgData.message;

// Se a mensagem contiver o comando de início/token, forçamos o início
if (message.toLowerCase().startsWith('iniciar cadastro')) {
  return { json: { step: 'INICIAR_CADASTRO', user, from: msgData.from, text: message } };
}

if (message.toLowerCase() === 'reconfigurar') {
  return { json: { step: 'RECONFIGURAR', user, from: msgData.from, text: message } };
}

// Caso contrário, seguimos a máquina de estados baseada na etapa atual salva
return {
  json: {
    step: user.etapa_conversa || 'NOVO_CADASTRO',
    user,
    from: msgData.from,
    text: message
  }
};

